# Deletion Script for Oogmatik Repository\n\nimport os\nimport shutil\n\n# Specify the current directory\nroot_dir = '.'  # Adjust this if running from a subdirectory\n\n# List of directories and files to delete\nitems_to_delete = [\n    'api', 'components', 'context', 'data', 'database', 'docs', 'hooks', 'kaynak', 'middleware',\n    'migrated_prompt_history', 'public', 'services', 'src', 'store', 'styles', 'tests', 'types', 'utils',\n    'package.json', 'tsconfig.json', 'App.tsx', 'index.tsx', 'constants.ts', 'registry.ts', 'types.ts', 'tailwind.config.js',\n    'vite.config.ts', 'postcss.config.js', 'vercel.json', 'swagger.yaml', '.env.example', '.eslintrc.json', '.gitignore',\n    '.prettierrc', 'index.html', 'global.d.ts', 'metadata.json', '1.pdf', 'Capture.svg', 'gitttt.bat',\n    'google42e59f2eb5b772e5.html'\n]\n\n# Delete the specified items\nfor item in items_to_delete:\n    path = os.path.join(root_dir, item)\n    if os.path.exists(path):\n        if os.path.isdir(path):\n            shutil.rmtree(path)  # Remove directory\n        else:\n            os.remove(path)  # Remove file\n\nprint('Deletion completed. All specified files and directories have been removed, except the oogmatik folder.')\n